import { useEvent } from "../hooks/use-event.js";
export function useOnRowsUpdated(onRowDataChange) {
    const onRowsUpdated = useEvent((rows) => {
        if (!onRowDataChange)
            return;
        const top = new Map();
        const center = new Map();
        const bottom = new Map();
        for (const [row, update] of rows.entries()) {
            if (row.kind === "branch")
                continue;
            const node = row;
            if (node.__pin === "top")
                top.set(node.__srcIndex, update);
            if (node.__pin === "center")
                center.set(node.__srcIndex, update);
            if (node.__pin === "bottom")
                bottom.set(node.__srcIndex, update);
        }
        onRowDataChange({ rows, top, center, bottom });
    });
    return onRowsUpdated;
}
